#include <cstdio>
#include <cstdlib>

constexpr int MAX_N = 27;

int n;
int solutions = 0;

void nqueen_kernel(int row, int ld, int cols, int rd, int &count, int all) {
    if (cols == all) {
        count++;
        return;
    }
    int pos = all & (~(ld | cols | rd));
    while (pos) {
        int bit = pos & (-pos);
        pos -= bit;
        nqueen_kernel(row + 1, (ld | bit) << 1, cols | bit, (rd | bit) >> 1, count, all);
    }
}

int main(int argc, char *argv[]) {
    if (argc != 2) {
        printf("Usage: %s <board_size>\n", argv[0]);
        return 1;
    }
    n = atoi(argv[1]);
    if (n < 1 || n > MAX_N) {
        printf("Board size must be between 1 and %d\n", MAX_N);
        return 1;
    }

    int all = (1 << n) - 1;
    int count = 0;

    #pragma omp target map(tofrom: count) map(to: n, all)
    {
        // We use a single thread to launch recursive calls on device
        // Because OpenMP target does not support recursion well,
        // we implement recursion on host and only offload the top-level call
        // So we do a single call here
        // Note: To fully offload recursion, more complex approaches are needed
        // but this keeps the code structure similar.

        // Use a lambda to capture count by reference
        struct {
            static void run(int row, int ld, int cols, int rd, int &count, int all) {
                if (cols == all) {
                    count++;
                    return;
                }
                int pos = all & (~(ld | cols | rd));
                while (pos) {
                    int bit = pos & (-pos);
                    pos -= bit;
                    run(row + 1, (ld | bit) << 1, cols | bit, (rd | bit) >> 1, count, all);
                }
            }
        } helper;

        helper.run(0, 0, 0, 0, count, all);
    }

    printf("Number of solutions for %d-queens problem: %d\n", n, count);

    return 0;
}
